# Main execution loop
main() {
    while true; do
        print_header
        show_menu
        read -rp "Your choice: " choice

        case $choice in
            1) run_dashboard_dev ;;
            2) build_dashboard ;;
            3) build_integration ;;
            4) copy_to_ha ;;
            5) deploy_to_ha_docker ;;
            6) run_tests ;;
            7) run_admin_tests ;;
            8) run_tests_coverage ;;
            9) run_tests_watch ;;
            10) lint_code ;;
            11) check_influxdb ;;
            12) open_grafana ;;
            13) install_deps ;;
            14) clean_project ;;
            15) generate_docs ;;
            16) setup_admin_credentials ;;
            17) open_admin_dashboard ;;
            18) show_help ;;
            q|Q) echo -e "${GREEN}👋 Goodbye!${NC}"; exit 0 ;;
            *) echo -e "${RED}Invalid option. Please try again.${NC}" ;;
        esac

        echo ""
        read -rp "Press Enter to continue..."
    done
}

# Check for command line arguments
if [ "$1" == "--help" ] || [ "$1" == "-h" ]; then
    show_help
    exit 0
fi

# Run main function
main "$@"